var items = $input.all();
var results = [];
var now = new Date().toISOString();

for (var i = 0; i < items.length; i++) {
  var data = items[i].json;

  // Handle RSS items
  if (data.title && (data.link || data.guid)) {
    results.push({ json: {
      title: data.title,
      url: data.link || data.guid || '',
      summary: (data.contentSnippet || data.description || '').replace(/<[^>]*>/g, '').substring(0, 500),
      source: data.creator || 'Gov.uk',
      opp_type: 'film-funding',
      discovered_at: now
    }});
    continue;
  }

  // Handle HTML pages - extract opportunity-like sections
  var html = data.data || data.body || '';
  if (typeof html !== 'string') continue;

  // Extract headings and links that look like opportunities
  var headings = html.match(/<h[2-4][^>]*>([^<]{5,150})<\/h[2-4]>/gi) || [];
  var sourceUrl = data.url || 'web-scrape';

  for (var h = 0; h < headings.length && h < 30; h++) {
    var title = headings[h].replace(/<[^>]*>/g, '').trim();
    var text = title.toLowerCase();
    if (text.indexOf('fund') >= 0 || text.indexOf('grant') >= 0 || text.indexOf('opportunity') >= 0 || text.indexOf('award') >= 0 || text.indexOf('scheme') >= 0 || text.indexOf('programme') >= 0 || text.indexOf('script') >= 0 || text.indexOf('writer') >= 0 || text.indexOf('talent') >= 0) {
      results.push({ json: {
        title: title,
        url: sourceUrl,
        summary: 'Found on: ' + sourceUrl,
        source: sourceUrl.indexOf('bbc') >= 0 ? 'BBC Writersroom' : sourceUrl.indexOf('bfi') >= 0 ? 'BFI' : sourceUrl.indexOf('screenskills') >= 0 ? 'ScreenSkills' : 'Web',
        opp_type: 'film-funding',
        discovered_at: now
      }});
    }
  }
}

// Deduplicate
var seen = {};
var unique = [];
for (var j = 0; j < results.length; j++) {
  var key = results[j].json.title.toLowerCase();
  if (!seen[key]) { seen[key] = true; unique.push(results[j]); }
}

return unique.length > 0 ? unique : [{ json: { title: 'No new opportunities today', url: '', summary: '', source: 'scanner', opp_type: 'film-funding', discovered_at: now } }];

var parsed = $('Parse Opportunities').all();
var now = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
var html = '<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">';
html += '<h1 style="color:#2c3e50;">Film & Screenwriting Opportunities</h1>';
html += '<p style="color:#666;">' + now + ' &bull; ' + parsed.length + ' items</p><hr>';
html += '<ul style="list-style:none;padding:0;">';
for (var i = 0; i < parsed.length; i++) {
  var item = parsed[i].json;
  html += '<li style="margin-bottom:10px;padding:8px;background:#f9f9f9;border-radius:4px;">';
  if (item.url) html += '<strong><a href="' + item.url + '" style="color:#2980b9;">' + item.title + '</a></strong>';
  else html += '<strong>' + item.title + '</strong>';
  if (item.summary) html += '<br><span style="color:#555;font-size:0.9em;">' + item.summary + '</span>';
  html += '<br><small style="color:#999;">Source: ' + item.source + '</small></li>';
}
html += '</ul><hr><p style="color:#999;font-size:0.8em;">Film Opps Scanner - Workhorse</p></div>';
return [{ json: { subject: 'Film & Script Opps - ' + now, html: html } }];
